const body = $input.first().json.body ?? $input.first().json;

if (body.data?.key?.fromMe === true) return [];
if (body.event !== 'messages.upsert') return [];

const data = body.data;
const remoteJid = data.key?.remoteJid;
if (!remoteJid) return [];
if (remoteJid.endsWith('@g.us')) return [];

const telefone = remoteJid.replace('@s.whatsapp.net', '');

let texto = '';
let tipoMensagem = data.messageType ?? 'unknown';

if (data.message?.conversation) {
  texto = data.message.conversation;
} else if (data.message?.extendedTextMessage?.text) {
  texto = data.message.extendedTextMessage.text;
} else if (data.message?.imageMessage?.caption) {
  texto = data.message.imageMessage.caption;
  tipoMensagem = 'imagem';
} else if (data.message?.audioMessage) {
  tipoMensagem = 'audio';
  texto = '[áudio]';
} else {
  return [];
}

if (!texto.trim()) return [];

return [{
  json: {
    telefone,
    nome: data.pushName ?? 'Cliente',
    texto: texto.trim(),
    tipoMensagem,
    messageId: data.key?.id ?? '',
    timestamp: data.messageTimestamp ?? Math.floor(Date.now() / 1000),
    instancia: body.instance ?? 'clinica',
    remoteJid
  }
}];

const { telefone, nome, texto, tipoMensagem, remoteJid, instancia, timestamp, messageId } = $input.first().json;

const systemPrompt = `Você é Aurora, recepcionista virtual de uma clínica de estética.\n\nClassifique a intenção da mensagem do cliente e gere uma resposta curta de transição.\n\nRetorne APENAS um JSON válido neste formato exato:\n{"intent": "INTENT", "confidence": 0.0, "resposta": "Frase de transição"}\n\nINTENÇÕES DISPONÍVEIS:\n- AGENDAR: marcar, desmarcar, reagendar, consultar horários/agenda\n- DUVIDA_PROCEDIMENTO: dúvidas sobre tratamentos, procedimentos, cuidados, indicações\n- DUVIDA_PRECO: valores, preços, promoções, pacotes, formas de pagamento\n- POS_PROCEDIMENTO: retorno pós-atendimento, efeitos, resultados, cuidados pós\n- LEAD_NOVO: primeiro contato, quer conhecer a clínica, sem histórico\n- RECLAMACAO: insatisfação, problema, crítica, urgência, pedido de reembolso\n- OUTRO: cumprimento genérico, áudio, não identificado\n\nTOM: Caloroso, profissional, máximo 2 frases curtas, máximo 1 emoji.\nUse o nome "${nome}" se disponível.\n\nResposta de transição = o que Aurora fala ANTES de passar para o especialista.\n\nResponda APENAS com o JSON. Nenhum texto adicional.`;

const userMessage = tipoMensagem === 'audio'
  ? '[cliente enviou áudio — use intent OUTRO e peça para escrever]'
  : texto;

return [{
  json: {
    telefone,
    nome,
    texto,
    tipoMensagem,
    remoteJid,
    instancia,
    timestamp,
    messageId,
    anthropicBody: {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 300,
      system: systemPrompt,
      messages: [
        { role: 'user', content: userMessage }
      ]
    }
  }
}];

const input = $input.first().json;
const ctx = $('Montar Prompt Haiku').first().json;

// FIX: trata erro HTTP da API Anthropic (rate limit, API key inválida, etc.)
if (input.error || !input.content) {
  return [{
    json: {
      telefone: ctx.telefone,
      nome: ctx.nome,
      texto: ctx.texto,
      tipoMensagem: ctx.tipoMensagem,
      remoteJid: ctx.remoteJid,
      instancia: ctx.instancia,
      timestamp: ctx.timestamp,
      messageId: ctx.messageId,
      intent: 'OUTRO',
      confidence: 0,
      resposta: `Oi, ${ctx.nome}! Estou com uma instabilidade agora. Pode me repetir em instantes? 😊`,
      haiku_raw: JSON.stringify(input.error ?? 'sem resposta da API')
    }
  }];
}

const rawText = input.content?.[0]?.text ?? '{}';

let parsed;
try {
  const cleaned = rawText.replace(/```json?/g, '').replace(/```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { intent: 'OUTRO', confidence: 0.5, resposta: 'Olá! Como posso te ajudar hoje? 😊' };
}

const validIntents = ['AGENDAR', 'DUVIDA_PROCEDIMENTO', 'DUVIDA_PRECO', 'POS_PROCEDIMENTO', 'LEAD_NOVO', 'RECLAMACAO', 'OUTRO'];
if (!validIntents.includes(parsed.intent)) {
  parsed.intent = 'OUTRO';
}

return [{
  json: {
    telefone: ctx.telefone,
    nome: ctx.nome,
    texto: ctx.texto,
    tipoMensagem: ctx.tipoMensagem,
    remoteJid: ctx.remoteJid,
    instancia: ctx.instancia,
    timestamp: ctx.timestamp,
    messageId: ctx.messageId,
    intent: parsed.intent,
    confidence: parsed.confidence ?? 0.8,
    resposta: parsed.resposta ?? 'Como posso te ajudar?',
    haiku_raw: rawText
  }
}];

const { telefone, nome, texto, intent, resposta, remoteJid, instancia, timestamp, messageId, confidence } = $input.first().json;

const mensagemParaCliente = resposta || `${nome}, sinto muito pelo inconveniente. Nossa equipe já foi notificada e entrará em contato em breve.`;

const mensagemParaEquipe =
  '🚨 *ESCALAÇÃO — ATENDIMENTO MANUAL NECESSÁRIO*\n\n' +
  `👤 Cliente: ${nome}\n` +
  `📱 Telefone: ${telefone}\n` +
  `💬 Mensagem: "${texto}"\n` +
  `🏷️ Intent: ${intent}\n\n` +
  'Por favor, assuma o atendimento manualmente.';

return [{
  json: {
    telefone,
    nome,
    texto,
    intent,
    confidence,
    remoteJid,
    instancia,
    timestamp,
    messageId,
    mensagemParaCliente,
    mensagemParaEquipe,
    ehEscalacao: true
  }
}];

const { telefone, nome, texto, intent, resposta, confidence, remoteJid, instancia, timestamp, messageId } = $input.first().json;

return [{
  json: {
    telefone,
    nome,
    texto,
    intent,
    confidence,
    remoteJid,
    instancia,
    timestamp,
    messageId,
    mensagemParaCliente: resposta,
    ehEscalacao: false
  }
}];
